import React, {useState, useEffect} from 'react';
import './App.css';
import './ProjectPage.css';
import transition from './transition.js';
import NavBar from './NavBar';
import Footer from './Footer';


import Cont_Clock from './projectContent/Cont_Clock';
import Thumb_Clock from './img/project/clock/thumb.jpg';
import Cont_Footwork from './projectContent/Cont_Footwork';
import Thumb_Footwork from './img/project/footwork/thumb.jpg';

import { useLocation } from 'react-router-dom';

const projComponentDict = {
  "footwork": [<Cont_Footwork thumbSrc={Thumb_Footwork}/>, Thumb_Footwork, "Footwork XVII", "Project Page Subtitle FW"],
  "clock": [<Cont_Clock />, Thumb_Clock, "Sequencer Clock", "CLOCK Project Page Subtitle"],
}


function ProjectPage() {
    var [projectKey, setProjectKey] = useState()
    var [projComponent, setProjComponent] = useState()
    var [projThumb, setProjThumb] = useState()
    const location = useLocation();

    useEffect(() => {
        var path = location.pathname
        var projectKeyRemoveSlash = path.slice(1)
        console.log("projectKey = ", projectKeyRemoveSlash)

        setProjectKey(projectKeyRemoveSlash)
        setProjComponent(projComponentDict[projectKeyRemoveSlash][0])
        setProjThumb(projComponentDict[projectKeyRemoveSlash][1])

        document.title = projComponentDict[projectKeyRemoveSlash][2]
    },[])



  return (
    <div>
      <NavBar></NavBar>

      {projComponent ? (
          projComponent     
      ) : ( <></>)}

      <Footer></Footer>
    </div>
  );
}

export default transition(ProjectPage);
